{"command": "cd $WORKSPACE_DIR && python3 - <<'PY'
from docx import Document
d = Document("output/key-terms-extraction-memo.docx")
print("Paragraphs:", len(d.paragraphs), "| Tables:", len(d.tables))
for i,t in enumerate(d.tables):
    print(f"Table {i}: {len(t.rows)} rows x {len(t.columns)} cols | header: {[c.text for c in t.rows[0].cells]}")
# show headings
print("\n--- Headings ---")
for p in d.paragraphs:
    if p.style.name.startswith("Heading"):
        print(f"[{p.style.name}] {p.text}")
